import{_ as r,o as s,c as a,ag as d,ah as t}from"./chunks/framework.D9bIGSBm.js";const u=JSON.parse('{"title":"快速上手","description":"","frontmatter":{},"headers":[],"relativePath":"guide/quick-start.md","filePath":"guide/quick-start.md"}'),n={name:"guide/quick-start.md"};function e(l,o,i,g,c,h){return s(),a("div",null,[...o[0]||(o[0]=[d('<h1 id="快速上手" tabindex="-1">快速上手 <a class="header-anchor" href="#快速上手" aria-label="Permalink to &quot;快速上手&quot;">​</a></h1><p>本页按照零基础用户第一次打开 LoongCode 的时间线，一步一步带你完成第一次 AI 对话。如果你还没有安装 CLI 或配置账号，请先阅读<a href="/docs/guide/prerequisites.html">前置依赖</a>。</p><h2 id="首次启动-跟着新手引导走" tabindex="-1">首次启动：跟着新手引导走 <a class="header-anchor" href="#首次启动-跟着新手引导走" aria-label="Permalink to &quot;首次启动：跟着新手引导走&quot;">​</a></h2><p>第一次打开 LoongCode 时，界面中央会自动弹出<strong>新手引导</strong>。引导共分 5 章，每章聚焦一个主题：</p><table tabindex="0"><thead><tr><th>章节</th><th>内容</th></tr></thead><tbody><tr><td><strong>起步</strong></td><td>欢迎 → 打开工作区 → 新建任务 → 设置 claude（即配置 Claude CLI，界面原文如此）→ 发送首条消息</td></tr><tr><td><strong>看代码</strong></td><td>目录树 → 查看文件 → 编辑文件</td></tr><tr><td><strong>进阶选项</strong></td><td>模型 → 思考深度 → 执行授权 → 浏览器标签页</td></tr><tr><td><strong>Git</strong></td><td>分支 → 审查</td></tr><tr><td><strong>设置</strong></td><td>常规 → 模型供应商 → 插件 → 技能 → MCP 服务器 → 使用统计</td></tr></tbody></table><p>引导中带实操闸门的步骤需要你完成对应动作才会自动跳到下一步；其他步骤点<strong>下一步</strong>即可前进。你也可以随时点<strong>跳过此步</strong>或<strong>退出引导</strong>。</p><p>引导结束后，可在<strong>设置 → 常规 → 使用引导</strong>处按章重看，或点<strong>从头重看</strong>重新体验完整流程。</p><div class="tip custom-block"><p class="custom-block-title">没有引导怎么办？</p><p>如果引导弹窗被意外关闭，打开<strong>设置 → 常规</strong>，找到<strong>使用引导</strong>区域，点击<strong>从头重看</strong>即可重新开启。</p></div><p><img src="'+t+'" alt="截图：LoongCode 首次启动界面，新手引导弹窗居中显示「欢迎使用 LoongCode」步骤卡片，突出引导章节导航与「下一步」按钮"></p><h2 id="第-1-步-打开工作区" tabindex="-1">第 1 步：打开工作区 <a class="header-anchor" href="#第-1-步-打开工作区" aria-label="Permalink to &quot;第 1 步：打开工作区&quot;">​</a></h2><p><strong>工作区</strong>就是你要让 AI 帮你处理的项目文件夹。打开工作区之后，AI 才能读取其中的代码和文件。</p><p>下面两条路径<strong>二选一</strong>即可。初次尝试推荐路径 A，后续步骤也以它为例；想直接用自己的项目就走路径 B，之后的操作完全相同。</p><p><strong>路径 A：使用示例工作区（推荐初次尝试）</strong></p><ol><li>在新手引导「打开工作区」步骤中，点击<strong>打开示例工作区</strong>按钮。</li><li>LoongCode 会自动创建并打开一个内含 README、脚本和笔记的示例项目文件夹。</li><li>左侧任务栏中出现示例工作区的名称，说明已成功打开。</li></ol><p><strong>路径 B：打开自己的项目</strong></p><ol><li>点击左侧任务栏中搜索框下方的**＋ 打开工作区**按钮。</li><li>在文件选择对话框中找到你的项目文件夹并确认。</li></ol><h2 id="第-2-步-新建任务" tabindex="-1">第 2 步：新建任务 <a class="header-anchor" href="#第-2-步-新建任务" aria-label="Permalink to &quot;第 2 步：新建任务&quot;">​</a></h2><p><strong>任务</strong>是一次独立的 AI 会话——每个任务拥有自己的对话记录、配置和上下文，互不干扰。</p><ol><li>点击左侧任务栏中搜索框下方的**＋ 新建任务**按钮。</li><li>中央区域切换为<strong>草稿态</strong>——草稿是任务还未正式开始时的预备状态，首条消息发送后任务才正式创建。</li></ol><div class="tip custom-block"><p class="custom-block-title">另一个入口</p><p>把鼠标移到左侧任务栏中的工作区名称上，名称右侧会出现<strong>新建任务</strong>图标，点击它同样可以在该工作区下新建任务。</p></div><div class="tip custom-block"><p class="custom-block-title">草稿会记住上次配置</p><p>新建任务时，CLI、模型、思考深度、执行授权等选项默认继承上一次任务的设置，无需每次重新调整。</p></div><p><img src="'+t+'" alt="截图：LoongCode 主界面，中央对话区显示草稿态界面，突出左侧「＋ 新建任务」按钮与中央输入框区域"></p><h2 id="第-3-步-配置任务-可全部保持默认" tabindex="-1">第 3 步：配置任务（可全部保持默认） <a class="header-anchor" href="#第-3-步-配置任务-可全部保持默认" aria-label="Permalink to &quot;第 3 步：配置任务（可全部保持默认）&quot;">​</a></h2><p>草稿态界面底部的<strong>选择器条</strong>显示当前任务的所有配置项。对于初次使用，默认值即可满足大多数需求。</p><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th><th>新手建议</th></tr></thead><tbody><tr><td><strong>CLI</strong></td><td>选择驱动引擎：Claude CLI（Anthropic 出品）或 Codex CLI（OpenAI 出品）</td><td>保持 <strong>Claude CLI</strong></td></tr><tr><td><strong>模型</strong></td><td>选择具体的 AI 模型</td><td>保持默认</td></tr><tr><td><strong>思考深度</strong></td><td>控制 AI 的推理深度，越深越细致但更慢；Claude 选项：low / medium / high / xhigh / max / ultracode</td><td>保持默认（出厂默认为 <strong>max</strong>），嫌慢可调低至 <strong>high</strong></td></tr><tr><td><strong>执行授权</strong></td><td>控制 AI 执行文件操作和命令的方式；选项：default / plan / acceptEdits / bypassPermissions</td><td>建议改为 <strong>default</strong>（每步操作先征求确认；出厂默认为 <strong>bypassPermissions</strong>，即完全自主执行）</td></tr><tr><td><strong>工作区</strong></td><td>当前任务关联的项目文件夹</td><td>无需修改</td></tr><tr><td><strong>分支</strong></td><td>当前 Git 分支（仅对 Git 仓库显示）</td><td>无需修改</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">首次使用需要先配置 API 密钥</p><p>如果你还没有配置过账号或 API 密钥，AI 将无法正常应答。请先前往<strong>设置 → 模型供应商</strong>完成配置，再回来发消息。</p></div><p><img src="'+t+'" alt="截图：LoongCode 草稿态界面底部，选择器条展开显示 CLI、模型、思考深度、执行授权下拉选项，突出各配置项"></p><h2 id="第-4-步-发送第一条消息" tabindex="-1">第 4 步：发送第一条消息 <a class="header-anchor" href="#第-4-步-发送第一条消息" aria-label="Permalink to &quot;第 4 步：发送第一条消息&quot;">​</a></h2><p>输入框的占位提示为：「向 Claude 提问，输入 @ 添加文件，/ 使用命令，$ 使用技能」</p><ol><li>点击中央输入框，光标出现在框内。</li><li>输入你的问题。对于示例工作区，可以试试：「介绍一下这个工作区里有什么」</li><li>按 <strong>Enter</strong> 键（或点击<strong>发送</strong>按钮）发送消息。</li></ol><p>消息发出后，草稿态结束，任务正式创建，AI 开始处理你的请求。</p><div class="tip custom-block"><p class="custom-block-title">输入框触发器</p><ul><li>输入 <code>@</code> — 从工作区文件列表选择文件，添加到对话上下文</li><li>输入 <code>/</code> — 打开命令面板，使用内置命令（如 <code>/compact</code> 压缩对话上下文）、插件命令和<strong>技能</strong></li></ul></div><h2 id="第-5-步-看懂-ai-的回复" tabindex="-1">第 5 步：看懂 AI 的回复 <a class="header-anchor" href="#第-5-步-看懂-ai-的回复" aria-label="Permalink to &quot;第 5 步：看懂 AI 的回复&quot;">​</a></h2><h3 id="回复的几种形态" tabindex="-1">回复的几种形态 <a class="header-anchor" href="#回复的几种形态" aria-label="Permalink to &quot;回复的几种形态&quot;">​</a></h3><ul><li><strong>流式文字</strong>：AI 的文字回答实时逐字显示，Markdown 格式自动渲染。</li><li><strong>思考过程</strong>（折叠块）：当思考深度高于 low 时，AI 会先输出内部推理过程，默认折叠显示为「思考过程」，点击可展开查看。</li><li><strong>工具卡片</strong>：AI 执行文件操作时会出现带状态图标的卡片，例如「读取文件」「写入文件」「执行命令」；修改代码时会显示 Diff（代码差异）。</li><li><strong>提问卡片</strong>：当执行授权设为 default 或 plan 时，AI 需要你确认才能继续操作——卡片上会出现<strong>允许</strong> / <strong>拒绝</strong>等按钮。</li></ul><p><img src="'+t+'" alt="截图：LoongCode 对话区，AI 正在流式输出回复，显示思考过程折叠块与工具卡片，突出卡片状态图标"></p><h3 id="任务状态" tabindex="-1">任务状态 <a class="header-anchor" href="#任务状态" aria-label="Permalink to &quot;任务状态&quot;">​</a></h3><p>左侧任务栏中，每个任务行左侧有一个小圆点，用<strong>颜色</strong>指示任务状态，用<strong>明暗</strong>指示有没有未读消息：</p><table tabindex="0"><thead><tr><th>状态</th><th>圆点外观</th><th>含义</th></tr></thead><tbody><tr><td><strong>空闲</strong></td><td>绿色</td><td>AI 已停止，等待你输入下一条消息</td></tr><tr><td><strong>运行中</strong></td><td>琥珀色，发光</td><td>AI 正在处理请求</td></tr><tr><td><strong>成功</strong></td><td>绿色</td><td>最近一轮对话正常结束</td></tr><tr><td><strong>出错</strong></td><td>红色</td><td>最近一轮对话发生错误</td></tr><tr><td><strong>提问中</strong></td><td>蓝色，发光</td><td>AI 正在等你回答提问卡片中的问题</td></tr></tbody></table><p>圆点不会闪烁——「运行中」和「提问中」通过<strong>发光光晕</strong>来提醒你。此外，有未读新消息的任务圆点<strong>明亮</strong>，你查看之后会变<strong>暗淡</strong>（「运行中」除外，它始终明亮）。每种指示灯的完整说明见<a href="/docs/features/tasks-and-workspaces.html#任务状态">任务与工作区</a>。</p><blockquote><p>「提问中」时，输入框占位提示会变为「请在上方卡片作答;或在此草拟下一条消息…」（界面原文如此）。</p></blockquote><p><img src="'+t+'" alt="截图：LoongCode 对话区，AI 提问卡片弹出等待用户作答，突出卡片中的选项与输入框占位符变化"></p><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>完成第一次对话后，建议了解主界面的完整布局——前往<a href="/docs/guide/interface-overview.html">界面导览</a>了解每个区域的功能，或直接进入<a href="/docs/features/tasks-and-workspaces.html">任务与工作区</a>学习更多使用技巧。</p>',44)])])}const b=r(n,[["render",e]]);export{u as __pageData,b as default};
